<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f5f5f5; color: #333; line-height: 1.6; }

  .container { max-width: 800px; margin: 0 auto; padding: 20px; }
  h1 { text-align: center; margin-bottom: 24px; font-size: 1.5rem; }

  /* Form */
  .form-card { background: #fff; border-radius: 8px; padding: 20px; box-shadow: 0 1px 3px rgba(0,0,0,.1); margin-bottom: 24px; }
  .form-row { display: flex; gap: 12px; align-items: flex-end; flex-wrap: wrap; }
  .form-group { display: flex; flex-direction: column; }
  .form-group label { font-size: .85rem; margin-bottom: 4px; font-weight: 600; }
  input, select { padding: 8px 10px; border: 1px solid #ccc; border-radius: 4px; font-size: .95rem; }
  input:focus, select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,.2); }

  button#add-expense { background: #4a90d9; color: #fff; border: none; padding: 8px 20px; border-radius: 4px; cursor: pointer; font-size: .95rem; white-space: nowrap; margin-top: auto; }
  button#add-expense:hover { background: #3a7bc8; }

  #form-error { color: #d9534f; font-size: .85rem; margin-top: 10px; min-height: 1.2em; }

  /* Summary */
  .summary-bar { display: flex; justify-content: space-between; align-items: center; background: #fff; border-radius: 8px; padding: 16px 20px; box-shadow: 0 1px 3px rgba(0,0,0,.1); margin-bottom: 24px; }
  .summary-bar h2 { font-size: 1.1rem; }
  #total { font-size: 1.5rem; font-weight: 700; color: #4a90d9; }

  /* Category totals */
  .cat-totals { display: flex; gap: 8px; margin-bottom: 24px; flex-wrap: wrap; }
  .cat-total { background: #fff; border-radius: 6px; padding: 10px 16px; box-shadow: 0 1px 3px rgba(0,0,0,.1); font-size: .9rem; display: flex; align-items: center; gap: 8px; }
  .cat-total span { font-weight: 700; color: #4a90d9; min-width: 50px; text-align: right; }

  /* Filters */
  .filters { background: #fff; border-radius: 8px; padding: 16px 20px; box-shadow: 0 1px 3px rgba(0,0,0,.1); margin-bottom: 24px; display: flex; gap: 12px; align-items: center; flex-wrap: wrap; }
  .filters select { min-width: 150px; }

  /* Expense list */
  #expense-list { background: #fff; border-radius: 8px; box-shadow: 0 1px 3px rgba(0,0,0,.1); overflow: hidden; }
  .expense { display: flex; justify-content: space-between; align-items: center; padding: 14px 20px; border-bottom: 1px solid #eee; }
  .expense:last-child { border-bottom: none; }
  .expense-info { display: flex; gap: 16px; align-items: baseline; }
  .expense-amount { font-weight: 700; color: #d9534f; min-width: 80px; text-align: right; }
  .expense-category { background: #e8eef5; padding: 2px 10px; border-radius: 12px; font-size: .8rem; font-weight: 600; color: #4a90d9; }
  .expense-date { font-size: .85rem; color: #777; }
  button.exp-del { background: none; border: none; cursor: pointer; color: #aaa; font-size: 1.2rem; padding: 4px 8px; border-radius: 4px; transition: all .15s; }
  button.exp-del:hover { color: #d9534f; background: #fce4e6; }

  .empty-msg { text-align: center; padding: 40px; color: #aaa; font-size: .95rem; }
</style>
</head>
<body>
<div class="container">
  <h1>Expense Tracker</h1>

  <!-- Entry Form -->
  <div class="form-card">
    <form id="expense-form" onsubmit="addExpense(event)">
      <div class="form-row">
        <div class="form-group">
          <label for="amount">Amount ($)</label>
          <input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00">
        </div>
        <div class="form-group">
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div class="form-group">
          <label for="date">Date</label>
          <input type="date" id="date" required>
        </div>
        <div class="form-group">
          <label for="note">Note (optional)</label>
          <input type="text" id="note" placeholder="Optional note...">
        </div>
        <button type="submit" id="add-expense">Add Expense</button>
      </div>
      <div id="form-error"></div>
    </form>
  </div>

  <!-- Summary -->
  <div class="summary-bar">
    <h2>Total (visible)</h2>
    <span id="total">$0.00</span>
  </div>

  <!-- Category Totals -->
  <div class="cat-totals" id="cat-totals"></div>

  <!-- Filters -->
  <div class="filters">
    <label for="filter-category">Category:</label>
    <select id="filter-category">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
    <label for="filter-from">From:</label>
    <input type="date" id="filter-from">
    <label for="filter-to">To:</label>
    <input type="date" id="filter-to">
  </div>

  <!-- Expense List -->
  <div id="expense-list"></div>
</div>

<script>
(function() {
  // --- State ---
  let expenses = [];

  // --- Persistence ---
  function loadExpenses() {
    try {
      const raw = localStorage.getItem('expenses');
      if (raw) expenses = JSON.parse(raw);
    } catch(e) { expenses = []; }
  }
  function saveExpenses() {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }

  // --- Validation ---
  function validateAmount(val) {
    const trimmed = val.trim();
    if (trimmed === '') return 'Amount is required.';
    const num = Number(trimmed);
    if (isNaN(num)) return 'Please enter a valid number.';
    if (num <= 0) return 'Amount must be greater than zero.';
    return null;
  }

  function validateDate(val) {
    if (!val || val === '') return 'A date is required.';
    const d = new Date(val + 'T00:00:00'); // normalize to midnight UTC
    if (isNaN(d.getTime())) return 'Please enter a valid date.';
    return null;
  }

  function showError(msg) {
    const el = document.getElementById('form-error');
    el.textContent = msg || '';
  }

  // --- Add Expense ---
  function addExpense(e) {
    e.preventDefault();
    const amountInput = document.getElementById('amount');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const categorySelect = document.getElementById('category');

    let err = validateAmount(amountInput.value);
    if (err) { showError(err); return; }

    err = validateDate(dateInput.value);
    if (err) { showError(err); return; }

    // Valid — clear error and reset amount
    const expense = {
      id: Date.now().toString(36) + Math.random().toString(36).slice(2, 7),
      amount: parseFloat(amountInput.value),
      category: categorySelect.value,
      date: dateInput.value,
      note: noteInput.value.trim() || null
    };

    expenses.push(expense);
    saveExpenses();
    showError('');
    amountInput.value = '';
    renderAll();
  }

  // --- Delete Expense ---
  function deleteExpense(id) {
    expenses = expenses.filter(x => x.id !== id);
    saveExpenses();
    renderAll();
  }

  // --- Filtering ---
  function getFilterCategory() { return document.getElementById('filter-category').value; }
  function getFilterFrom() { return document.getElementById('filter-from').value || ''; }
  function getFilterTo() { return document.getElementById('filter-to').value || ''; }

  function isDateInRange(expense) {
    const from = getFilterFrom();
    const to = getFilterTo();
    if (!from && !to) return true;
    if (from && expense.date < from) return false;
    if (to && expense.date > to) return false;
    return true;
  }

  function isCategoryMatch(expense) {
    const cat = getFilterCategory();
    if (cat === 'all') return true;
    return expense.category === cat;
  }

  function getVisibleExpenses() {
    return expenses.filter(isCategoryMatch).filter(isDateInRange);
  }

  // --- Rendering ---
  function renderAll() {
    const visible = getVisibleExpenses();
    renderList(visible);
    renderSummary(visible);
    renderCatTotals(visible);
  }

  function renderList(expenses) {
    const listEl = document.getElementById('expense-list');
    if (expenses.length === 0) {
      listEl.innerHTML = '<div class="empty-msg">No expenses to display.</div>';
      return;
    }
    listEl.innerHTML = expenses.map(e => `
      <div class="expense" data-id="${e.id}">
        <div class="expense-info">
          <span class="expense-amount">$${e.amount.toFixed(2)}</span>
          <span class="expense-category">${e.category}</span>
          <span class="expense-date">${e.date}${e.note ? ' — ' + e.note : ''}</span>
        </div>
        <button class="exp-del" data-id="${e.id}" title="Delete">&times;</button>
      </div>
    `).join('');

    // Attach delete handlers (re-bind after innerHTML)
    listEl.querySelectorAll('.exp-del').forEach(btn => {
      btn.addEventListener('click', function() {
        const id = this.getAttribute('data-id');
        deleteExpense(id);
      });
    });
  }

  function renderSummary(expenses) {
    const totalEl = document.getElementById('total');
    if (expenses.length === 0) {
      totalEl.textContent = '$0.00';
      return;
    }
    const sum = expenses.reduce((s, e) => s + e.amount, 0);
    totalEl.textContent = '$' + sum.toFixed(2);
  }

  function renderCatTotals(expenses) {
    const catSet = new Set(expenses.map(e => e.category));
    const container = document.getElementById('cat-totals');
    if (container.children.length === 0 && catSet.size === 0) return;

    // Clear existing .cat-total elements
    container.querySelectorAll('.cat-total').forEach(el => el.remove());

    for (const cat of catSet) {
      const sum = expenses.filter(e => e.category === cat).reduce((s, e) => s + e.amount, 0);
      const div = document.createElement('div');
      div.className = 'cat-total';
      div.setAttribute('data-cat', cat);
      div.innerHTML = `<span>$${sum.toFixed(2)}</span> ${cat.charAt(0).toUpperCase() + cat.slice(1)}`;
      container.appendChild(div);
    }
  }

  // --- Event Listeners ---
  document.getElementById('expense-form').addEventListener('submit', addExpense);

  // Re-render on filter changes (without re-adding expenses to state)
  ['filter-category', 'filter-from', 'filter-to'].forEach(id => {
    document.getElementById(id).addEventListener('change', renderAll);
  });

  // --- Init ---
  loadExpenses();
  // Set today's date as default in the form
  const today = new Date().toISOString().slice(0, 10);
  document.getElementById('date').value = today;
  renderAll();
})();
</script>
</body>
</html>
